 14→@Injectable()
 15→export class OpensearchService implements OnModuleInit {
 16→	private readonly logger = new Logger(OpensearchService.name);
 17→	private client: Client;
 18→	private host: string;
 19→	private username: string;
 20→	private password: string;
 21→
 22→	constructor(private readonly configService: EnvConfigService) {}
 23→
 24→	onModuleInit(): void {
 25→		this.initializeOpensearchClient();
 26→	}
