333→	@LogExecution()
334→	async createSearchPipeline({
335→		pipelineId,
336→		normalizationTechnique = 'min_max',
337→		combinationTechnique = 'arithmetic_mean',
338→		weights = [0.2, 0.8],
339→		ragConfig,
340→	}: {
341→		pipelineId: string;
342→		normalizationTechnique?: string;
343→		combinationTechnique?: string;
344→		weights?: number[];
345→		ragConfig?: {
346→			modelId: string;
347→			contextFieldList: string[];
348→			systemPrompt: string;
349→			userInstructions: string;
350→		};
351→	}): Promise<void> {
352→		try {
353→			const body: Record<string, unknown> = {
354→				description: `Hybrid search pipeline: ${normalizationTechnique} + ${combinationTechnique}`,
355→				phase_results_processors: [
356→					{
357→						'normalization-processor': {
358→							normalization: { technique: normalizationTechnique },
359→							combination: { technique: combinationTechnique, parameters: { weights } },
360→						},
361→					},
362→				],
363→			};
364→
365→			if (ragConfig) {
366→				body['response_processors'] = [
367→					{
368→						retrieval_augmented_generation: {
369→							tag: 'rag_processor',
370→							model_id: ragConfig.modelId,
371→							context_field_list: ragConfig.contextFieldList,
372→							system_prompt: ragConfig.systemPrompt,
373→							user_instructions: ragConfig.userInstructions,
374→						},
375→					},
376→				];
377→			}
378→
379→			await this.client.transport.request({
380→				method: 'PUT',
381→				path: `/_search/pipeline/${pipelineId}`,
382→				body,
383→			});
384→			this.logger.log(`Created search pipeline: ${pipelineId}`);
385→		} catch (error: unknown) {
386→			this.handleError({
387→				context: `Failed to create search pipeline ${pipelineId}`,
388→				error,
389→			});
390→			throw error;
391→		}
392→	}
