400→	async search({
401→		indexName,
402→		body,
403→		searchPipeline,
404→	}: {
405→		indexName: string;
406→		body: Record<string, unknown>;
407→		searchPipeline?: string;
408→	}): Promise<{
409→		hits: { _id: string; _score: number; _source: Record<string, unknown> }[];
410→		ext?: Record<string, unknown>;
411→	}> {
412→		try {
413→			const searchParams: Record<string, unknown> = { index: indexName, body };
414→
415→			if (searchPipeline) {
416→				searchParams['search_pipeline'] = searchPipeline;
417→			}
418→
419→			const response = await this.client.search(searchParams);
420→
421→			const responseBody = response.body as {
422→				hits: {
423→					hits: { _id: string; _score: number; _source: Record<string, unknown> }[];
424→				};
425→				ext?: Record<string, unknown>;
426→			};
427→
428→			const hits = responseBody.hits.hits.map((hit) => ({
429→				_id: hit._id,
430→				_score: hit._score,
431→				_source: hit._source,
432→			}));
433→
434→			const result: {
435→				hits: { _id: string; _score: number; _source: Record<string, unknown> }[];
436→				ext?: Record<string, unknown>;
437→			} = { hits };
438→
439→			if (responseBody.ext !== undefined) {
440→				result.ext = responseBody.ext;
441→			}
442→
443→			return result;
444→		} catch (error: unknown) {
445→			this.handleError({ context: `Search failed on index ${indexName}`, error });
446→			throw error;
447→		}
448→	}
