122→	private detectBrand({ text }: { text: string }): string | null {
123→		const sorted = [...NEURAL_SEARCH_KNOWN_BRANDS].sort((a, b) => b.length - a.length);
124→		for (const brand of sorted) {
125→			const escaped = brand.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
126→			if (new RegExp(`\\b${escaped}\\b`, 'i').test(text)) {
127→				return brand;
128→			}
129→		}
130→		return null;
131→	}
