133→	private readonly GENDER_PRODUCT_TYPE_MAP: {
134→		pattern: RegExp;
135→		productTypes: string[];
136→	}[] = [
137→		{
138→			pattern: /\b(women|woman|womens|women's|female|ladies|lady|girls|girl's)\b/i,
139→			productTypes: ["Women's"],
140→		},
141→		{
142→			pattern: /\b(men|man|mens|men's|male|guys|guy)\b/i,
143→			productTypes: ['Unisex'],
144→		},
145→		{
146→			pattern: /\b(youth|kids|kid|children|child|toddler|infant|baby|juvenile)\b/i,
147→			productTypes: ['Youth'],
148→		},
149→	];
150→
151→	detectGenderProductTypes({ text }: { text: string }): string[] | null {
152→		const productTypes: string[] = [];
153→
154→		for (const { pattern, productTypes: types } of this.GENDER_PRODUCT_TYPE_MAP) {
155→			if (pattern.test(text)) {
156→				productTypes.push(...types);
157→			}
158→		}
159→
160→		return productTypes.length > 0 ? productTypes : null;
161→	}
