163→	private readonly PRICE_LEVEL_MAP: { pattern: RegExp; levels: number[] }[] = [
164→		{
165→			pattern:
166→				/\b(cheap|budget|affordable|inexpensive|low[\s-]cost|economical|bargain|value|discount|basic|entry[\s-]level)\b/i,
167→			levels: [1],
168→		},
169→		{
170→			pattern:
171→				/\b(mid[\s-]range|midrange|moderate|average|standard|medium|middle|reasonable|fair price|mid price)\b/i,
172→			levels: [2],
173→		},
174→		{
175→			pattern:
176→				/\b(premium|luxury|high[\s-]end|expensive|upscale|top[\s-]tier|deluxe|elite|designer|exclusive|finest)\b/i,
177→			levels: [3],
178→		},
179→	];
180→
181→	detectPriceLevels({ text }: { text: string }): number[] | null {
182→		const levels: number[] = [];
183→
184→		for (const { pattern, levels: priceLevels } of this.PRICE_LEVEL_MAP) {
185→			if (pattern.test(text)) {
186→				levels.push(...priceLevels);
187→			}
188→		}
189→
190→		return levels.length > 0 ? levels : null;
191→	}
