193→	sanitizeQuery({ text }: { text: string }): string {
194→		return text
195→			.trim()
196→			.replace(/<[^>]*>/g, ' ')
197→			.replace(/[\x00-\x1F\x7F]/g, ' ')
198→			.replace(/[^a-zA-Z0-9\s\-'&]/g, ' ')
199→			.replace(/\s{2,}/g, ' ')
200→			.substring(0, NEURAL_SEARCH_MAX_QUERY_LENGTH)
201→			.trim();
202→	}
