383→		const searchBody: Record<string, unknown> = {
384→			size,
385→			min_score: 0.4,
386→			query: {
387→				hybrid: {
388→					queries: [
389→						{ bool: { should: [...priceBoosts, ...brandBoosts], filter: baseFilters } },
390→						{
391→							neural: {
392→								product_embedding: {
393→									query_text: normalizedQuery,
394→									model_id: this.getEmbeddingModelId(),
395→									k: size * 5,
396→									filter: { bool: { filter: baseFilters } },
397→								},
398→							},
399→						},
400→					],
401→				},
402→			},
403→			collapse: { field: 'product_id' },
404→			_source: { excludes: ['product_embedding', 'combined_text_for_embedding'] },
405→		};
406→
407→		if (memoryId && llmQuestion) {
408→			searchBody['ext'] = {
409→				generative_qa_parameters: {
410→					llm_question: llmQuestion,
411→					llm_model: 'gpt-4o-mini',
412→					memory_id: memoryId,
413→					context_size: 5,
414→					message_size: 5,
415→					timeout: 15,
416→				},
417→			};
418→		}
419→
420→		const result = await this.opensearchService.search({
421→			indexName: this.indexName,
422→			searchPipeline: 'conversational-hybrid-search-pipeline',
423→			body: searchBody,
424→		});
425→
426→		const products = result.hits.map((hit) => ({
427→			...(hit._source as IOpensearchProduct),
428→			_id: hit._id,
429→		}));
430→
431→		const ragData = result.ext?.['retrieval_augmented_generation'] as
432→			| { answer?: string }
433→			| undefined;
434→
435→		const answer = ragData?.answer;
436→
437→		const searchResult: { products: IOpensearchProduct[]; answer?: string } = {
438→			products,
439→		};
440→
441→		if (answer !== undefined) {
442→			searchResult.answer = answer;
443→		}
444→
445→		return searchResult;
446→	}
