448→	private normalizeCondensedFeatures({
449→		condensedFeatures,
450→	}: {
451→		condensedFeatures: unknown;
452→	}): string[] | null {
453→		if (condensedFeatures === null || condensedFeatures === undefined) {
454→			return null;
455→		}
456→
457→		if (typeof condensedFeatures === 'string') {
458→			return [condensedFeatures];
459→		}
460→
461→		if (Array.isArray(condensedFeatures)) {
462→			return condensedFeatures.map(String);
463→		}
464→
465→		if (typeof condensedFeatures === 'object') {
466→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
467→				Array.isArray(value) ? value.map(String) : [String(value)],
468→			);
469→		}
470→
471→		return [JSON.stringify(condensedFeatures)];
472→	}
473→
474→	private buildCombinedTextForEmbedding({ style }: { style: IStylesMvBase }): string {
475→		const normalizedCondensedFeatures = this.normalizeCondensedFeatures({
476→			condensedFeatures: style.condensed_features,
477→		});
478→		const priceLvlMap: Record<string, string> = {
479→			1: 'Budget',
480→			2: 'Mid-range',
481→			3: 'Premium',
482→		};
483→		const mappedPriceLevel: string | null =
484→			style.price_level && priceLvlMap[String(style.price_level)]
485→				? (priceLvlMap[String(style.price_level)] ?? null)
486→				: (priceLvlMap['2'] ?? null);
487→
488→		const parts: string[] = [
489→			...(style.name ? [this.cleanText({ text: style.name })] : []),
490→			...(style.product_type ? [this.cleanText({ text: style.product_type })] : []),
491→			...(mappedPriceLevel ? [`Price lvl: ${mappedPriceLevel}`] : []),
492→			...(style.brand?.length
493→				? [`Brand: ${this.cleanText({ text: style.brand[0] })}`]
494→				: []),
495→			...(normalizedCondensedFeatures?.length
496→				? [this.cleanText({ text: normalizedCondensedFeatures.join(', ') })]
497→				: []),
498→			...(style.style_type ? [this.cleanText({ text: style.style_type })] : []),
499→			...(style.primary_category_name
500→				? [`Category: ${this.cleanText({ text: style.primary_category_name })}`]
501→				: []),
502→			...(style.manufacturer
503→				? [`From: ${this.cleanText({ text: style.manufacturer })}`]
504→				: []),
505→			...(style.sub_category_names?.length
506→				? [
507→						`Subcategories: ${this.cleanText({ text: style.sub_category_names.join(', ') })}`,
508→					]
509→				: []),
510→			...(style.decoration_method
511→				? [`Decoration: ${this.cleanText({ text: style.decoration_method })}`]
512→				: []),
513→			...(style.features
514→				? [`Features: ${this.cleanText({ text: style.features })}`]
515→				: []),
516→		];
517→
518→		const combinedText = parts.filter(Boolean).join('. ');
519→
520→		this.logger.debug(
521→			`Combined text length for style_id ${style.style_id}: ${combinedText.length} characters`,
522→		);
523→
524→		return combinedText;
525→	}
526→
527→	private cleanText({ text }: { text: string | null | undefined }): string {
528→		if (!text) return '';
529→		return text
530→			.replace(/\r\n|\r|\n/g, ' ')
531→			.replace(/[*#]+\s?/g, '')
532→			.replace(/<[^>]*>/g, '')
533→			.replace(/\s{2,}/g, ' ')
534→			.trim();
535→	}
