 58→	): Promise<void> {
 59→		if (this.isShuttingDown) {
 60→			this.logger.warn('Command cancelled due to shutdown signal');
 61→			return;
 62→		}
 63→
 64→		const modelFormat = options.modelFormat ?? 'TORCH_SCRIPT';
 65→		const batchSize = options.batchSize ?? 60;
