 70→
 71→		try {
 72→			const indexName = this.configService.get<string>({
 73→				key: OPENSEARCH_CONVERSATIONAL_INDEX_NAME,
 74→			});
 75→			const openAiApiKey = this.configService.get<string>({ key: OPENAI_API_KEY });
 76→
 77→			let step = 1;
 78→
 79→			if (cleanup) {
 80→				this.logger.log(
 81→					`=== Step ${step++}/${totalSteps}: Cleaning up existing conversational search resources ===`,
 82→				);
 83→				await this.cleanupExistingResources({ indexName });
 84→			}
 85→
 86→			this.logger.log(
 87→				`=== Step ${step++}/${totalSteps}: Configuring cluster ML settings ===`,
 88→			);
 89→			await this.opensearchService.configureClusterMLSettings();
 90→			await this.configureConversationalMLSettings();
 91→
 92→			this.logger.log(`=== Step ${step++}/${totalSteps}: Registering model group ===`);
 93→			const modelGroupId = await this.opensearchService.registerModelGroup({
 94→				name: CONV_MODEL_GROUP_NAME,
 95→				description: 'Model group for conversational search (embedding + LLM)',
 96→			});
 97→
 98→			this.logger.log(
 99→				`=== Step ${step++}/${totalSteps}: Registering embedding model (this may take several minutes) ===`,
100→			);
101→			const embeddingRegisterTaskId = await this.opensearchService.registerModel({
102→				name: CONV_MODEL_NAME,
103→				version: CONV_MODEL_VERSION,
104→				modelGroupId,
105→				modelFormat,
106→			});
107→
108→			this.logger.log('Waiting for embedding model registration to complete...');
109→			const embeddingRegisterResult = await this.opensearchService.waitForTask({
110→				taskId: embeddingRegisterTaskId,
111→				intervalMs: 10000,
112→				maxAttempts: 120,
113→			});
114→			const embeddingModelId = embeddingRegisterResult.model_id;
115→
116→			if (!embeddingModelId) {
117→				throw new Error(
118→					'Embedding model registration completed but no model_id returned',
119→				);
120→			}
121→
122→			this.logger.log(`Embedding model registered: ${embeddingModelId}`);
123→
124→			this.logger.log(
125→				`=== Step ${step++}/${totalSteps}: Deploying embedding model (this may take several minutes) ===`,
126→			);
127→			const embeddingDeployTaskId = await this.opensearchService.deployModel({
128→				modelId: embeddingModelId,
129→			});
130→
131→			this.logger.log('Waiting for embedding model deployment to complete...');
132→			await this.opensearchService.waitForTask({
133→				taskId: embeddingDeployTaskId,
134→				intervalMs: 10000,
135→				maxAttempts: 120,
136→			});
137→			this.logger.log('Embedding model deployed successfully');
138→
139→			this.logger.log(`=== Step ${step++}/${totalSteps}: Creating OpenAI connector ===`);
140→			const connectorId = await this.opensearchService.createConnector({
141→				name: `openai-${OPENAI_LLM_MODEL_NAME}-connector`,
142→				openAiApiKey,
143→				modelName: OPENAI_LLM_MODEL_NAME,
144→			});
145→
146→			this.logger.log(
147→				`=== Step ${step++}/${totalSteps}: Registering LLM model via connector ===`,
148→			);
149→			const llmRegisterTaskId = await this.opensearchService.registerRemoteModel({
150→				name: OPENAI_LLM_MODEL_NAME,
151→				connectorId,
152→				modelGroupId,
153→			});
154→
155→			this.logger.log('Waiting for LLM model registration to complete...');
156→			const llmRegisterResult = await this.opensearchService.waitForTask({
157→				taskId: llmRegisterTaskId,
158→				intervalMs: 5000,
159→				maxAttempts: 60,
160→			});
161→			const llmModelId = llmRegisterResult.model_id;
162→
163→			if (!llmModelId) {
164→				throw new Error('LLM model registration completed but no model_id returned');
165→			}
166→
167→			this.logger.log(`LLM model registered: ${llmModelId}`);
168→
169→			this.logger.log(`=== Step ${step++}/${totalSteps}: Deploying LLM model ===`);
170→			const llmDeployTaskId = await this.opensearchService.deployModel({
171→				modelId: llmModelId,
172→			});
173→
174→			this.logger.log('Waiting for LLM model deployment to complete...');
175→			await this.opensearchService.waitForTask({
176→				taskId: llmDeployTaskId,
177→				intervalMs: 5000,
178→				maxAttempts: 60,
179→			});
180→			this.logger.log('LLM model deployed successfully');
181→
182→			this.logger.log(`=== Step ${step++}/${totalSteps}: Creating ingest pipeline ===`);
183→			await this.opensearchService.createIngestPipeline({
184→				pipelineId: CONV_INGEST_PIPELINE_ID,
185→				modelId: embeddingModelId,
186→				sourceField: 'combined_text_for_embedding',
187→				targetField: 'product_embedding',
188→			});
189→
190→			this.logger.log(`=== Step ${step++}/${totalSteps}: Creating search pipeline ===`);
191→			await this.opensearchService.createSearchPipeline({
192→				pipelineId: CONV_SEARCH_PIPELINE_ID,
193→				normalizationTechnique: 'min_max',
194→				combinationTechnique: 'arithmetic_mean',
195→				weights: [0.1, 0.9],
196→				ragConfig: {
197→					modelId: llmModelId,
198→					contextFieldList: [
199→						'name',
200→						'features',
201→						'manufacturer',
202→						'product_type',
203→						'brand',
204→						'general_comments',
205→						'primary_category_name',
206→						'condensed_features',
207→					],
208→					systemPrompt: `You are an expert product recommendation assistant for a promotional products store.
209→						 Your goal is to understand the customer's full intent and surface the most relevant products.
210→						 When analyzing a request always identify:
211→						 (1) GENDER/AUDIENCE — who the products are for: men, women, youth, or mixed/unisex group;
212→						 (2) OCCASION/USE CASE — the intended use: casual everyday, sports/outdoor, corporate/business, events/fundraisers, school, or team use;
213→						 (3) PRICE PREFERENCE — budget level: budget, mid-range, or premium;
214→						 (4) PRODUCT TYPE — the category: apparel, bags, drinkware, headwear, accessories, etc.
215→						 Use these signals to give targeted, relevant recommendations.
216→						 When prior conversation context is available, reference it naturally to show continuity.`,
217→					userInstructions: `Based on the customer request, their inferred intent (gender/audience, occasion, price range, product type), and the matched products,
218→						 write a concise 1-2 sentence response that:
219→						 (1) acknowledges what the customer is looking for using their own words;
220→						 (2) explains why the found products are a good match — mention gender fit, occasion suitability, price range, or brand;
221→						 (3) ends with an invitation to refine or follow up if needed.
222→						 Be friendly, specific, and brief. Never list all products — summarize the selection.`,
223→				},
224→			});
225→
226→			this.logger.log(
227→				`=== Step ${step++}/${totalSteps}: Creating index ${indexName} ===`,
228→			);
229→			await this.opensearchConversationalService.createProductsIndex({ indexName });
230→
231→			if (this.isCancelled) {
232→				this.logger.warn('Bootstrap cancelled before product sync');
233→				return;
234→			}
235→
236→			this.logger.log(
237→				`=== Step ${step}/${totalSteps}: Syncing products (embedding generation on ingest) ===`,
238→			);
239→			this.logger.log(`Batch size: ${batchSize}, Concurrency: ${concurrency}`);
240→
241→			const totalCount = await this.stylesMvModel.count();
242→			this.logger.log(`Total products to index: ${totalCount}`);
243→
244→			if (totalCount === 0) {
245→				this.logger.warn('No products found to index');
246→				return;
247→			}
248→
249→			const totalBatches = Math.ceil(totalCount / batchSize);
250→			const batches = Array.from({ length: totalBatches }, (_, i) => ({
251→				offset: i * batchSize,
252→				limit: batchSize,
253→			}));
254→
255→			const progressBar = new ProgressBar({ total: totalCount });
256→			let totalIndexed = 0;
257→			let totalErrors = 0;
258→
259→			this.currentOperation = this.processBatches({
260→				batches,
261→				concurrency,
262→				indexName,
263→				progressBar,
264→				onBatchComplete: (indexed, errors) => {
265→					totalIndexed += indexed;
266→					totalErrors += errors;
267→				},
268→			});
269→
270→			await this.currentOperation;
271→
272→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
273→			if (!this.isCancelled) {
274→				progressBar.finish();
275→			}
276→
277→			const duration = ((Date.now() - startTime) / 1000).toFixed(1);
278→
279→			this.logger.log('=== Bootstrap complete ===');
280→			this.logger.log(`Duration: ${duration}s`);
281→			this.logger.log(`Products indexed: ${totalIndexed}, Errors: ${totalErrors}`);
282→			this.logger.log(
283→				`Embedding model ID: ${embeddingModelId}, LLM model ID: ${llmModelId}`,
284→			);
285→		} catch (error) {
286→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
287→			if (this.isShuttingDown || this.isCancelled) {
288→				this.logger.warn('Command interrupted during shutdown');
289→				return;
290→			}
291→			this.logger.error(`Bootstrap failed: ${(error as Error).message}`);
292→			process.exit(1);
293→		} finally {
294→			this.currentOperation = null;
295→		}
296→	}
