397→				});
398→			},
399→			onItemComplete: (result) => {
400→				progressBar.increment(result.indexed + result.errors);
401→				onBatchComplete(result.indexed, result.errors);
402→			},
403→			onItemError: (error) => {
404→				this.logger.error(`Batch processing error: ${(error as Error).message}`);
405→			},
406→		});
407→	}
408→
409→	@Option({
410→		flags: '-f, --model-format <modelFormat>',
411→		description: 'Model format: TORCH_SCRIPT or ONNX (default: TORCH_SCRIPT)',
412→	})
413→	parseModelFormat(value: string): string {
